// wireframes.jsx — sketchy lo-fi wireframes demonstrating Cdesign capabilities
// All artboards share the marker-on-paper vibe: rough borders, handwritten labels,
// B&W with one orange accent. Designed to fit inside <DCArtboard> cards.

// ───────────────────────────────── shared bits ─────────────────────────────────

const ink = '#1a1a1a';
const ink2 = '#3a3a3a';
const muted = '#9a9a9a';
const paper = '#fbf8f1';
const accent = '#ff5a1f'; // signal orange
const accent2 = '#fcd34d'; // highlighter yellow

// Rough border using layered box-shadows + a slight rotation per stroke.
// Cheaper than SVG filters and survives DOM edits cleanly.
const rough = (color = ink, w = 2) => ({
  border: `${w}px solid ${color}`,
  borderRadius: '6px 8px 5px 9px / 7px 5px 9px 6px',
  boxShadow: `0 0 0 0.5px ${color}33, 1px 1.5px 0 ${color}22`,
});

const handFont = "'Caveat', cursive";
const bodyFont = "'Kalam', cursive";
const monoFont = "'JetBrains Mono', ui-monospace, monospace";

// Wobbly underline (svg) — pure decoration
const Squiggle = ({ w = 60, h = 8, color = accent, strokeWidth = 2 }) => (
  <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{ display: 'block' }}>
    <path
      d={`M 2 ${h/2} Q ${w*0.2} 1, ${w*0.4} ${h/2} T ${w*0.8} ${h/2} T ${w-2} ${h/2}`}
      fill="none"
      stroke={color}
      strokeWidth={strokeWidth}
      strokeLinecap="round"
    />
  </svg>
);

// Hand-drawn arrow
const Arrow = ({ x1, y1, x2, y2, color = ink, strokeWidth = 2, dashed = false }) => {
  const dx = x2 - x1, dy = y2 - y1;
  const mx = (x1 + x2) / 2 + dy * 0.08;
  const my = (y1 + y2) / 2 - dx * 0.08;
  const ang = Math.atan2(y2 - my, x2 - mx);
  const ah = 8;
  return (
    <g>
      <path
        d={`M ${x1} ${y1} Q ${mx} ${my}, ${x2} ${y2}`}
        fill="none"
        stroke={color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={dashed ? '4 4' : 'none'}
      />
      <path
        d={`M ${x2} ${y2} L ${x2 - ah*Math.cos(ang - 0.4)} ${y2 - ah*Math.sin(ang - 0.4)}
            M ${x2} ${y2} L ${x2 - ah*Math.cos(ang + 0.4)} ${y2 - ah*Math.sin(ang + 0.4)}`}
        fill="none"
        stroke={color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />
    </g>
  );
};

// A placeholder image rectangle — diagonal stripes + label
const ImgBox = ({ w = 80, h = 60, label = 'IMG', style }) => (
  <div style={{
    width: w, height: h, position: 'relative',
    background: `repeating-linear-gradient(45deg, transparent 0 6px, ${ink}11 6px 7px)`,
    ...rough(ink2, 1.5),
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    fontFamily: monoFont, fontSize: 9, color: ink2, letterSpacing: 0.5,
    ...style,
  }}>{label}</div>
);

// Scribbled text bar — represents a line of text without committing to copy
const TextBar = ({ w = '100%', h = 6, opacity = 0.65, style }) => (
  <div style={{
    width: w, height: h, background: ink, borderRadius: h/2,
    opacity, ...style,
  }} />
);

// Wireframe label tag — used as artboard caption inside the board
const Tag = ({ children, color = accent, style }) => (
  <div style={{
    display: 'inline-block', padding: '2px 8px',
    background: color, color: '#fff',
    fontFamily: handFont, fontSize: 16, fontWeight: 700,
    borderRadius: '4px 8px 5px 7px',
    transform: 'rotate(-1deg)',
    boxShadow: `1px 1px 0 ${ink}33`,
    ...style,
  }}>{children}</div>
);

// Sticky note
const Sticky = ({ children, color = accent2, rot = -2, style }) => (
  <div style={{
    background: color, padding: '8px 10px',
    fontFamily: handFont, fontSize: 14, color: ink,
    transform: `rotate(${rot}deg)`,
    boxShadow: '2px 3px 8px rgba(0,0,0,0.15)',
    lineHeight: 1.2, maxWidth: 140,
    ...style,
  }}>{children}</div>
);

// Wrapper that fills an artboard with paper + a light grid
const Board = ({ children, pad = 24, style }) => (
  <div style={{
    width: '100%', height: '100%', background: paper,
    backgroundImage: `radial-gradient(${ink}0a 1px, transparent 1px)`,
    backgroundSize: '14px 14px',
    padding: pad, boxSizing: 'border-box',
    fontFamily: bodyFont, color: ink,
    position: 'relative', overflow: 'hidden',
    ...style,
  }}>{children}</div>
);

// Section heading inside an artboard
const BoardHeading = ({ title, sub, num }) => (
  <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12, marginBottom: 16 }}>
    <div style={{
      fontFamily: handFont, fontSize: 36, lineHeight: 1,
      color: accent, fontWeight: 700, transform: 'rotate(-3deg)',
      flex: '0 0 auto',
    }}>#{num}</div>
    <div style={{ flex: 1 }}>
      <div style={{ fontFamily: handFont, fontSize: 30, fontWeight: 700, lineHeight: 1, color: ink }}>
        {title}
      </div>
      <Squiggle w={120} h={6} />
      <div style={{ fontFamily: bodyFont, fontSize: 12, color: ink2, marginTop: 4 }}>
        {sub}
      </div>
    </div>
  </div>
);

// ───────────────────────────────── 1. SLIDE DECKS ─────────────────────────────────

const WF_Decks = () => {
  const Slide = ({ children, rot = 0, style }) => (
    <div style={{
      background: '#fff', ...rough(ink, 2),
      transform: `rotate(${rot}deg)`,
      padding: 10, display: 'flex', flexDirection: 'column', gap: 4,
      ...style,
    }}>{children}</div>
  );
  return (
    <Board>
      <BoardHeading num="01" title="Decks" sub="HTML slides with scaling + PDF export + speaker notes" />
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14, marginTop: 8 }}>
        <Slide rot={-1.5}>
          <div style={{ fontFamily: handFont, fontSize: 22, fontWeight: 700, lineHeight: 1 }}>Title slide</div>
          <Squiggle w={80} />
          <TextBar w="70%" h={4} />
          <TextBar w="50%" h={4} />
          <div style={{ marginTop: 'auto', display: 'flex', justifyContent: 'space-between' }}>
            <span style={{ fontFamily: monoFont, fontSize: 8, color: muted }}>01 / 12</span>
          </div>
        </Slide>
        <Slide rot={1}>
          <div style={{ fontFamily: handFont, fontSize: 16, fontWeight: 700 }}>Section header</div>
          <div style={{ flex: 1, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
            <ImgBox w="100%" h="100%" label="chart" />
            <div style={{ display: 'flex', flexDirection: 'column', gap: 4, justifyContent: 'center' }}>
              <TextBar w="100%" h={3} />
              <TextBar w="80%" h={3} />
              <TextBar w="90%" h={3} />
            </div>
          </div>
        </Slide>
        <Slide rot={2}>
          <div style={{ fontFamily: handFont, fontSize: 16, fontWeight: 700 }}>Full-bleed image</div>
          <ImgBox w="100%" h={70} label="hero" />
          <TextBar w="60%" h={3} />
        </Slide>
        <Slide rot={-1}>
          <div style={{ fontFamily: handFont, fontSize: 16, fontWeight: 700 }}>Quote</div>
          <div style={{
            fontFamily: handFont, fontSize: 14, lineHeight: 1.1,
            borderLeft: `3px solid ${accent}`, paddingLeft: 8, marginTop: 4, color: ink2,
          }}>"the proof is in<br />the pudding"</div>
          <span style={{ fontFamily: monoFont, fontSize: 7, color: muted, marginTop: 'auto' }}>— anon.</span>
        </Slide>
      </div>
      <div style={{ position: 'absolute', bottom: 14, left: 24, right: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
          <span style={{ fontFamily: monoFont, fontSize: 10, color: ink2 }}>→ export</span>
          <Tag color={ink} style={{ fontSize: 12, padding: '1px 6px' }}>.pptx</Tag>
          <Tag color={ink} style={{ fontSize: 12, padding: '1px 6px' }}>.pdf</Tag>
          <Tag color={ink} style={{ fontSize: 12, padding: '1px 6px' }}>canva</Tag>
        </div>
        <Sticky rot={3} style={{ fontSize: 12, padding: '4px 6px' }}>speaker<br/>notes ✓</Sticky>
      </div>
    </Board>
  );
};

// ───────────────────────────────── 2. INTERACTIVE PROTOTYPES ─────────────────────────────────

const WF_Prototype = () => {
  const Phone = ({ rot = 0, label, children, style }) => (
    <div style={{
      width: 110, height: 200, background: '#fff', ...rough(ink, 2),
      borderRadius: 18, padding: 8, boxSizing: 'border-box',
      transform: `rotate(${rot}deg)`,
      display: 'flex', flexDirection: 'column', gap: 5,
      position: 'relative', ...style,
    }}>
      <div style={{ position: 'absolute', top: 4, left: '50%', transform: 'translateX(-50%)', width: 30, height: 4, background: ink, borderRadius: 2 }} />
      <div style={{ height: 8 }} />
      {children}
      <div style={{ position: 'absolute', bottom: -18, left: '50%', transform: 'translateX(-50%)', fontFamily: monoFont, fontSize: 9, color: ink2, whiteSpace: 'nowrap' }}>{label}</div>
    </div>
  );
  return (
    <Board>
      <BoardHeading num="02" title="Prototypes" sub="hi-fi, clickable, real interactions" />
      <div style={{ position: 'relative', height: 280, marginTop: 8 }}>
        <svg style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
          <Arrow x1={140} y1={120} x2={195} y2={120} color={accent} />
          <Arrow x1={325} y1={120} x2={380} y2={120} color={accent} />
          <Arrow x1={380} y1={170} x2={325} y2={170} color={ink} dashed />
        </svg>
        <Phone rot={-2} label="login" style={{ position: 'absolute', left: 16, top: 18 }}>
          <ImgBox w="100%" h={36} label="logo" />
          <TextBar w="100%" h={6} style={{ background: '#fff', border: `1px solid ${ink}55`, borderRadius: 3 }} />
          <TextBar w="100%" h={6} style={{ background: '#fff', border: `1px solid ${ink}55`, borderRadius: 3 }} />
          <div style={{ background: accent, color: '#fff', textAlign: 'center', padding: '4px 0', fontFamily: handFont, fontSize: 12, fontWeight: 700, ...rough(ink, 1) }}>sign in</div>
        </Phone>
        <Phone rot={1} label="dashboard" style={{ position: 'absolute', left: 200, top: 28 }}>
          <TextBar w="50%" h={8} />
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 4 }}>
            <ImgBox w="100%" h={28} label="" />
            <ImgBox w="100%" h={28} label="" />
            <ImgBox w="100%" h={28} label="" />
            <ImgBox w="100%" h={28} label="" />
          </div>
          <TextBar w="80%" h={4} />
          <TextBar w="60%" h={4} />
        </Phone>
        <Phone rot={-1.5} label="detail" style={{ position: 'absolute', left: 384, top: 18 }}>
          <ImgBox w="100%" h={50} label="hero" />
          <TextBar w="80%" h={6} />
          <TextBar w="100%" h={4} />
          <TextBar w="100%" h={4} />
          <TextBar w="60%" h={4} />
          <div style={{ marginTop: 'auto', background: ink, color: '#fff', textAlign: 'center', padding: '4px 0', fontFamily: handFont, fontSize: 11, fontWeight: 700 }}>buy now</div>
        </Phone>
      </div>
      <div style={{ position: 'absolute', bottom: 14, left: 24, right: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 12 }}>
        <Sticky color={accent2} rot={-2} style={{ fontSize: 12, padding: '4px 8px' }}>real state +<br/>real navigation</Sticky>
        <div style={{ display: 'flex', gap: 6 }}>
          <Tag color={ink} style={{ fontSize: 11, padding: '1px 6px' }}>iOS frame</Tag>
          <Tag color={ink} style={{ fontSize: 11, padding: '1px 6px' }}>Android</Tag>
          <Tag color={ink} style={{ fontSize: 11, padding: '1px 6px' }}>macOS</Tag>
        </div>
      </div>
    </Board>
  );
};

// ───────────────────────────────── 3. ANIMATED VIDEOS ─────────────────────────────────

const WF_Animation = () => {
  const Keyframe = ({ t, label, color = accent }) => (
    <div style={{ position: 'absolute', top: -8, left: `${t}%`, transform: 'translateX(-50%)' }}>
      <div style={{ width: 12, height: 12, background: color, ...rough('#fff', 1.5), borderRadius: '50%', boxShadow: `0 0 0 2px ${paper}` }} />
      <div style={{ fontFamily: monoFont, fontSize: 8, color: ink2, marginTop: 4, whiteSpace: 'nowrap', transform: 'translateX(-30%)' }}>{label}</div>
    </div>
  );
  const Layer = ({ name, segs }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
      <div style={{ width: 70, fontFamily: monoFont, fontSize: 10, color: ink2, textAlign: 'right' }}>{name}</div>
      <div style={{ flex: 1, height: 14, position: 'relative', background: '#fff', ...rough(ink2, 1) }}>
        {segs.map((s, i) => (
          <div key={i} style={{
            position: 'absolute', top: 1, bottom: 1,
            left: `${s[0]}%`, width: `${s[1] - s[0]}%`,
            background: s[2] || accent, opacity: 0.85,
            borderRadius: 2,
          }} />
        ))}
      </div>
    </div>
  );
  return (
    <Board>
      <BoardHeading num="03" title="Animated video" sub="timeline + scrubber + easing curves" />
      <div style={{
        background: '#fff', ...rough(ink, 2), padding: '20px 16px 12px', marginTop: 8,
        position: 'relative',
      }}>
        <div style={{ position: 'relative', marginBottom: 14, height: 18 }}>
          <div style={{ position: 'absolute', left: 78, right: 0, top: '50%', height: 1, background: ink2 }} />
          <Keyframe t={5} label="0:00" color={ink} />
          <Keyframe t={28} label="enter" />
          <Keyframe t={52} label="hold" color={accent2} />
          <Keyframe t={75} label="exit" />
          <Keyframe t={96} label="end" color={ink} />
          <div style={{ position: 'absolute', left: '40%', top: -4, bottom: -4, width: 2, background: ink, opacity: 0.9 }} />
        </div>
        <Layer name="title" segs={[[8, 38, accent]]} />
        <Layer name="hero img" segs={[[28, 78, ink]]} />
        <Layer name="subtitle" segs={[[42, 70, accent2]]} />
        <Layer name="cta button" segs={[[60, 95, accent]]} />
      </div>
      <div style={{ display: 'flex', gap: 14, marginTop: 16, alignItems: 'center' }}>
        <div style={{ flex: 1, ...rough(ink, 2), background: '#fff', padding: 10 }}>
          <div style={{ fontFamily: monoFont, fontSize: 9, color: ink2, marginBottom: 4 }}>EASING</div>
          <svg width="100%" height="40" viewBox="0 0 100 40">
            <path d="M 4 36 Q 30 36, 60 6 T 96 4" fill="none" stroke={accent} strokeWidth="2.5" strokeLinecap="round" />
            <circle cx="4" cy="36" r="2.5" fill={ink} />
            <circle cx="96" cy="4" r="2.5" fill={ink} />
          </svg>
        </div>
        <Sticky rot={3}>play • pause • scrub<br/>built in 🎬</Sticky>
      </div>
    </Board>
  );
};

// ───────────────────────────────── 4. DESIGN EXPLORATION ─────────────────────────────────

const WF_Exploration = () => {
  const Mini = ({ rot = 0, label, children, style }) => (
    <div style={{
      background: '#fff', ...rough(ink, 1.5),
      padding: 8, transform: `rotate(${rot}deg)`,
      display: 'flex', flexDirection: 'column', gap: 4,
      position: 'relative', ...style,
    }}>
      {children}
      <div style={{ position: 'absolute', top: -16, left: 0, fontFamily: handFont, fontSize: 13, color: ink2 }}>{label}</div>
    </div>
  );
  return (
    <Board>
      <BoardHeading num="04" title="Many options" sub="explore directions on one canvas, fullscreen any one" />
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 18, marginTop: 18 }}>
        <Mini rot={-1.5} label="A · classic">
          <TextBar w="60%" h={6} />
          <ImgBox w="100%" h={40} label="" />
          <TextBar w="90%" h={3} />
          <TextBar w="70%" h={3} />
        </Mini>
        <Mini rot={1} label="B · bold">
          <div style={{ background: accent, height: 50, ...rough('#fff', 1), display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: handFont, color: '#fff', fontSize: 18, fontWeight: 700 }}>BIG</div>
          <TextBar w="80%" h={3} />
        </Mini>
        <Mini rot={-0.5} label="C · minimal">
          <div style={{ height: 50, borderBottom: `1px solid ${ink}` }}>
            <TextBar w="30%" h={4} style={{ marginTop: 20 }} />
          </div>
          <TextBar w="50%" h={3} />
        </Mini>
        <Mini rot={1.5} label="D · split">
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 4, height: 50 }}>
            <ImgBox w="100%" h="100%" label="" />
            <div style={{ background: ink, color: '#fff', padding: 6, fontFamily: handFont, fontSize: 11 }}>copy</div>
          </div>
        </Mini>
        <Mini rot={-1} label="E · stacked">
          <TextBar w="100%" h={4} />
          <TextBar w="100%" h={4} />
          <TextBar w="100%" h={4} />
          <ImgBox w="100%" h={20} label="" />
        </Mini>
        <Mini rot={0.5} label="F · ⌖ pick">
          <div style={{
            ...rough(accent, 2.5), padding: 4, background: `${accent}11`,
            height: 50, display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <span style={{ fontFamily: handFont, fontSize: 14, color: accent, fontWeight: 700 }}>★ winner</span>
          </div>
          <TextBar w="60%" h={3} />
        </Mini>
